{
  "claims": [
    {
      "claim_text": "The California Privacy Protection Agency supports SB 362, The Delete Act."
    },
    {
      "claim_text": "SB 362 allows Californians to delete their personal information from data brokers."
    },
    {
      "claim_text": "Data brokers collect, analyze, and sell personal information about consumers."
    },
    {
      "claim_text": "Data brokers aggregate data from public records, social media platforms, and online transactions."
    },
    {
      "claim_text": "Under the California Consumer Privacy Act (CCPA), consumers have a right to require a data broker to delete information they collected directly from them."
    },
    {
      "claim_text": "Data brokers do not have to report the types of information they collect and sell."
    },
    {
      "claim_text": "The CPPA would create a simple way for Californians to direct all data brokers to delete their personal information free of charge."
    },
    {
      "claim_text": "Data brokers that fail to adhere to the law would face civil penalties and administrative fines set by the CPPA."
    }
  ]
}
